import{_ as a,o,c as t,a4 as r}from"./chunks/framework.BE2Pea4t.js";const b=JSON.parse('{"title":"Interface: Form<S, I> · forms","description":"","frontmatter":{"title":"Interface: Form<S, I> · forms"},"headers":[],"relativePath":"api/forms/interfaces/Form.md","filePath":"api/forms/interfaces/Form.md"}'),s={name:"api/forms/interfaces/Form.md"};function d(c,e,n,i,l,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<p><a href="./../">@jsvision/forms</a> / Form</p><h1 id="interface-form-s-i" tabindex="-1">Interface: Form&lt;S, I&gt; <a class="header-anchor" href="#interface-form-s-i" aria-label="Permalink to &quot;Interface: Form\\&lt;S, I\\&gt;&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L59" target="_blank" rel="noreferrer">types.ts:59</a></p><p>The headless form store returned by <a href="./../functions/createForm.html">createForm</a>. It owns the raw editing values, validates the whole object through the schema, and exposes per-field and form-level accessors plus <code>submit</code> / <code>reset</code>. It draws nothing.</p><h2 id="type-parameters" tabindex="-1">Type Parameters <a class="header-anchor" href="#type-parameters" aria-label="Permalink to &quot;Type Parameters&quot;">​</a></h2><h3 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h3><p><code>S</code> <em>extends</em> <code>z.ZodObject</code>&lt;<code>z.ZodRawShape</code>&gt;</p><p>the Zod object schema type.</p><h3 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h3><p><code>I</code></p><p>the raw initial value shape (keys constrained to the schema).</p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><h3 id="dirty" tabindex="-1">dirty() <a class="header-anchor" href="#dirty" aria-label="Permalink to &quot;dirty()&quot;">​</a></h3><blockquote><p><strong>dirty</strong>(): <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L76" target="_blank" rel="noreferrer">types.ts:76</a></p><p>Whether any field diverges from its baseline.</p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>boolean</code></p><hr><h3 id="dispose" tabindex="-1">dispose() <a class="header-anchor" href="#dispose" aria-label="Permalink to &quot;dispose()&quot;">​</a></h3><blockquote><p><strong>dispose</strong>(): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L126" target="_blank" rel="noreferrer">types.ts:126</a></p><p>Tear down the form&#39;s whole reactive scope — the standing async-validation effects and every owned computed. Idempotent and safe to call more than once. A long-lived form need not call this, but a per-dialog form that mounts async validators should dispose it when the dialog closes so no debounce fires after teardown.</p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="errors" tabindex="-1">errors() <a class="header-anchor" href="#errors" aria-label="Permalink to &quot;errors()&quot;">​</a></h3><blockquote><p><strong>errors</strong>(): <code>$ZodIssue</code>[]</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L67" target="_blank" rel="noreferrer">types.ts:67</a></p><p>Form-level (path-less) validation issues, e.g. from an object-level <code>refine</code>.</p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>$ZodIssue</code>[]</p><hr><h3 id="field" tabindex="-1">field() <a class="header-anchor" href="#field" aria-label="Permalink to &quot;field()&quot;">​</a></h3><blockquote><p><strong>field</strong>&lt;<code>K</code>&gt;(<code>name</code>): <a href="./Field.html"><code>Field</code></a>&lt;<code>I</code>[<code>K</code>]&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L61" target="_blank" rel="noreferrer">types.ts:61</a></p><p>Get the stable handle for a field. Throws <code>FormFieldError</code> for an unknown key.</p><h4 id="type-parameters-1" tabindex="-1">Type Parameters <a class="header-anchor" href="#type-parameters-1" aria-label="Permalink to &quot;Type Parameters&quot;">​</a></h4><h5 id="k" tabindex="-1">K <a class="header-anchor" href="#k" aria-label="Permalink to &quot;K&quot;">​</a></h5><p><code>K</code> <em>extends</em> <code>string</code> | <code>number</code> | <code>symbol</code></p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="name" tabindex="-1">name <a class="header-anchor" href="#name" aria-label="Permalink to &quot;name&quot;">​</a></h5><p><code>K</code></p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><a href="./Field.html"><code>Field</code></a>&lt;<code>I</code>[<code>K</code>]&gt;</p><hr><h3 id="isvalid" tabindex="-1">isValid() <a class="header-anchor" href="#isvalid" aria-label="Permalink to &quot;isValid()&quot;">​</a></h3><blockquote><p><strong>isValid</strong>(): <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L74" target="_blank" rel="noreferrer">types.ts:74</a></p><p>Whether the whole object currently satisfies the schema <strong>and</strong> has no async error (live, independent of touched). Optimistic about pending async work: a field whose async validator has not yet run (or is still in flight) does not hold this <code>false</code> — only a resolved async error does. Adds no extra <code>safeParse</code> call.</p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>boolean</code></p><hr><h3 id="load" tabindex="-1">load() <a class="header-anchor" href="#load" aria-label="Permalink to &quot;load()&quot;">​</a></h3><blockquote><p><strong>load</strong>(<code>loader</code>): <code>Promise</code>&lt;<code>boolean</code>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L107" target="_blank" rel="noreferrer">types.ts:107</a></p><p>Load an existing record into the form: runs <code>loader</code> (given a fresh <code>AbortSignal</code>) and, on success, replaces every field&#39;s value and rebases the whole baseline to the loaded record in one batch, leaving the form pristine — <code>touched</code> / submit-attempted cleared and <code>dirty()</code> false, so <code>reset()</code> now returns to the LOADED record. Resolves <code>true</code> on success, <code>false</code> if the loader rejects (state untouched) — it never rejects. Re-invokable (a Reload button). A newer <code>load()</code> supersedes an older in-flight one; <code>dispose()</code> aborts an in-flight load. Do NOT call while a <code>submit()</code> is in flight (the two are independent; gate them in the app).</p><p>The loader must resolve the full RAW editing record (<code>Promise&lt;I&gt;</code>, the same shape as <code>initial</code>) — map your server/domain record to raw editing values inside it (there is no inverse of <code>z.coerce</code>). A key missing from the resolved record sets that field (and its baseline) to <code>undefined</code>.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="loader" tabindex="-1">loader <a class="header-anchor" href="#loader" aria-label="Permalink to &quot;loader&quot;">​</a></h5><p>(<code>ctx</code>) =&gt; <code>Promise</code>&lt;<code>I</code>&gt;</p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>Promise</code>&lt;<code>boolean</code>&gt;</p><hr><h3 id="loading" tabindex="-1">loading() <a class="header-anchor" href="#loading" aria-label="Permalink to &quot;loading()&quot;">​</a></h3><blockquote><p><strong>loading</strong>(): <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L92" target="_blank" rel="noreferrer">types.ts:92</a></p><p>Whether an async record load started by <a href="#load">Form.load</a> is currently in flight. Form-level and atomic (a whole record loads at once — there is no per-field loading). It does NOT gate <code>isValid()</code> / <code>submit()</code>; compose the busy state yourself (e.g. <code>disabled: () =&gt; form.loading()</code>).</p><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>boolean</code></p><hr><h3 id="rawvalues" tabindex="-1">rawValues() <a class="header-anchor" href="#rawvalues" aria-label="Permalink to &quot;rawValues()&quot;">​</a></h3><blockquote><p><strong>rawValues</strong>(): <code>I</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L65" target="_blank" rel="noreferrer">types.ts:65</a></p><p>The live raw editing snapshot — always available, independent of validity.</p><h4 id="returns-7" tabindex="-1">Returns <a class="header-anchor" href="#returns-7" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>I</code></p><hr><h3 id="reset" tabindex="-1">reset() <a class="header-anchor" href="#reset" aria-label="Permalink to &quot;reset()&quot;">​</a></h3><blockquote><p><strong>reset</strong>(): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L119" target="_blank" rel="noreferrer">types.ts:119</a></p><p>Restore every field to its baseline value and clear dirty + touched, in one batch.</p><h4 id="returns-8" tabindex="-1">Returns <a class="header-anchor" href="#returns-8" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="submit" tabindex="-1">submit() <a class="header-anchor" href="#submit" aria-label="Permalink to &quot;submit()&quot;">​</a></h3><blockquote><p><strong>submit</strong>(<code>onValid</code>): <code>Promise</code>&lt;<code>boolean</code>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L117" target="_blank" rel="noreferrer">types.ts:117</a></p><p>Mark every field touched, validate, and — when valid — await <code>onValid</code> with the coerced values. Resolves <code>true</code> when valid (after <code>onValid</code> completes) and <code>false</code> when invalid (without calling <code>onValid</code>).</p><p>The async-aware gate: it short-circuits <code>false</code> on a synchronously-invalid object (no async validator is invoked), otherwise it cancels pending debounces, force-runs and awaits every async validator, and gates on the combined result — so a value an async rule rejects never passes.</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="onvalid" tabindex="-1">onValid <a class="header-anchor" href="#onvalid" aria-label="Permalink to &quot;onValid&quot;">​</a></h5><p>(<code>values</code>) =&gt; <code>void</code> | <code>Promise</code>&lt;<code>void</code>&gt;</p><h4 id="returns-9" tabindex="-1">Returns <a class="header-anchor" href="#returns-9" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>Promise</code>&lt;<code>boolean</code>&gt;</p><hr><h3 id="submitting" tabindex="-1">submitting() <a class="header-anchor" href="#submitting" aria-label="Permalink to &quot;submitting()&quot;">​</a></h3><blockquote><p><strong>submitting</strong>(): <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L86" target="_blank" rel="noreferrer">types.ts:86</a></p><p>Whether a <a href="#submit">Form.submit</a> is currently in flight — <code>true</code> synchronously from the moment <code>submit()</code> is called until it settles (its validators <strong>and</strong> the <code>onValid</code> callback), <code>false</code> on every return path, including a <code>onValid</code> that throws. Form-level; it completes the <code>loading()</code> / <code>validating()</code> / <code>submitting()</code> in-flight trio. Bind a busy indicator or a <code>disabled</code> getter to it (e.g. <code>disabled: () =&gt; form.submitting()</code>).</p><h4 id="returns-10" tabindex="-1">Returns <a class="header-anchor" href="#returns-10" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>boolean</code></p><hr><h3 id="validating" tabindex="-1">validating() <a class="header-anchor" href="#validating" aria-label="Permalink to &quot;validating()&quot;">​</a></h3><blockquote><p><strong>validating</strong>(): <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L78" target="_blank" rel="noreferrer">types.ts:78</a></p><p>Whether any field is currently running an async validation.</p><h4 id="returns-11" tabindex="-1">Returns <a class="header-anchor" href="#returns-11" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>boolean</code></p><hr><h3 id="values" tabindex="-1">values() <a class="header-anchor" href="#values" aria-label="Permalink to &quot;values()&quot;">​</a></h3><blockquote><p><strong>values</strong>(): <code>output</code>&lt;<code>S</code>&gt; | <code>null</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/0fccac5d677bd47c0a4938eef02a0bcc5d29f78c/packages/forms/src/types.ts#L63" target="_blank" rel="noreferrer">types.ts:63</a></p><p>The coerced, schema-typed values when the form is valid, else <code>null</code>. Never throws.</p><h4 id="returns-12" tabindex="-1">Returns <a class="header-anchor" href="#returns-12" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>output</code>&lt;<code>S</code>&gt; | <code>null</code></p>',116)])])}const p=a(s,[["render",d]]);export{b as __pageData,p as default};
